const results = {};

for (const item of items) {
  const doc = item.json;
  const matchId = doc.Match_ID;
  const name = (doc.Document_name || "").toUpperCase();

  if (!results[matchId]) {
    results[matchId] = {
      Match_ID:        matchId,
      "Booking#":      doc["Booking#"]      || "N/A",
      "Booking type":  doc["Booking type"]  || "N/A",
      "Folder name":   doc["Folder name"]   || "N/A",
      Parent_ID:       doc.Parent_ID        || null,
      Child_ID:        doc.Child_ID         || matchId,
      Document_ID:     null,
      Document_name:   "No BL available",
      "BL_available?": "no",
      priority: 0
    };
  }

  let currentPriority = 0;

  if (name.includes("TR")) {
    currentPriority = 4;
  } else if (name.includes("HBL")) {
    currentPriority = 3;
  } else if (name.includes("BL") && !name.includes("DRAFT")) {
    currentPriority = 2;
  } else if (name.includes("DRAFT")) {
    currentPriority = 1;
  }

  if (currentPriority > results[matchId].priority) {
    results[matchId].Document_ID    = doc.Document_ID;
    results[matchId].Document_name  = doc.Document_name;
    results[matchId].priority       = currentPriority;
    results[matchId]["BL_available?"] = "yes";
  }
}

return Object.values(results).map(res => {
  const { priority, ...cleanResult } = res;
  return { json: cleanResult };
});

const results = {};

for (const item of items) {
  const doc = item.json;
  const matchId = doc.Match_ID;
  const name = (doc.Document_name || "").toUpperCase();

  if (!results[matchId]) {
    results[matchId] = {
      Match_ID:        matchId,
      "Booking#":      doc["Booking#"]      || "N/A",
      "Booking type":  doc["Booking type"]  || "N/A",
      "Folder name":   doc["Folder name"]   || "N/A",
      Parent_ID:       doc.Parent_ID        || null,
      Child_ID:        doc.Child_ID         || matchId,
      Document_ID:     null,
      Document_name:   "No PL available",
      "PL_available?": "no",
      priority: 0
    };
  }

  let currentPriority = 0;

  if (name.includes("PL") && !name.includes("DRAFT") && !name.includes("CI")) {
    currentPriority = 3;
  } else if (name.includes("PL") && !name.includes("DRAFT") && name.includes("CI")) {
    currentPriority = 2;
  } else if (name.includes("PL") && name.includes("DRAFT")) {
    currentPriority = 1;
  }

  if (currentPriority > results[matchId].priority) {
    results[matchId].Document_ID    = doc.Document_ID;
    results[matchId].Document_name  = doc.Document_name;
    results[matchId].priority       = currentPriority;
    results[matchId]["PL_available?"] = "yes";
  }
}

return Object.values(results).map(res => {
  const { priority, ...cleanResult } = res;
  return { json: cleanResult };
});

const getVal = (obj, path, fallback = 0) => {
  return path.split('.').reduce((acc, part) => acc && acc[part], obj) ?? fallback;
};

const workflowStart = new Date($('Start_Time').first().json.Workflow_Start);
const runtime = ((new Date() - workflowStart) / 1000).toFixed(1);

const STOP_WORDS = new Set(['the','and','of','for','a','an','in','to','with','by','at','from','on','is','are','as']);

const getKeywords = (str) => {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 1 && !STOP_WORDS.has(w));
};

const descriptionOverlap = (blDesc, plDesc) => {
  if (!blDesc || !plDesc || blDesc === 'N/A' || plDesc === 'N/A' ||
      blDesc === 'NOT_FOUND' || plDesc === 'NOT_FOUND') {
    return { status: '⚠️ UNAVAILABLE', detail: 'Description missing on BL or PL' };
  }
  const blWords = getKeywords(blDesc);
  const plWords = new Set(getKeywords(plDesc));
  if (blWords.length === 0) {
    return { status: '⚠️ UNAVAILABLE', detail: 'BL description could not be parsed' };
  }
  const matched = blWords.filter(w => plWords.has(w)).length;
  const overlap = matched / blWords.length;
  if (overlap >= 0.6) {
    return { status: '✅ MATCH', detail: `${Math.round(overlap * 100)}% keyword overlap` };
  } else {
    return { status: '❌ DISCREPANCY', detail: `${Math.round(overlap * 100)}% keyword overlap (below 60% threshold)` };
  }
};

return $input.all().map(({ json: input }) => {

  const bl = {
    factory:  input.BL_factory || {},
    metrics:  input.BL_logistics_metrics || {},
    product:  input.BL_cargo_description || "N/A",
  };

  const pl = {
    factory:  input.PL_factory || {},
    metrics:  input.PL_logistics_metrics || {},
    product:  input.PL_cargo_description || "N/A"
  };

  // ── Check 1: Weight & Volume ───────────────────────────────
  const blWeight = getVal(bl, 'metrics.gross_weight_kg');
  const plWeight = getVal(pl, 'metrics.gross_weight_kg');
  const blVolume = getVal(bl, 'metrics.volume_cbm');
  const plVolume = getVal(pl, 'metrics.volume_cbm');

  const weightDiff = Math.abs(plWeight - blWeight).toFixed(2);
  const volDiff    = Math.abs(plVolume - blVolume).toFixed(3);

  let weightStatus, volumeStatus;

  if (blWeight === 0 && plWeight === 0) {
    weightStatus = '⚠️ UNAVAILABLE (missing on both BL and PL)';
  } else if (blWeight === 0) {
    weightStatus = '⚠️ UNAVAILABLE (missing on BL)';
  } else if (plWeight === 0) {
    weightStatus = '⚠️ UNAVAILABLE (missing on PL)';
  } else if (parseFloat(weightDiff) > 1.0) {
    weightStatus = `❌ DISCREPANCY (${weightDiff}kg variance)`;
  } else {
    weightStatus = '✅ MATCH';
  }

  if (blVolume === 0 && plVolume === 0) {
    volumeStatus = '⚠️ UNAVAILABLE (missing on both BL and PL)';
  } else if (blVolume === 0) {
    volumeStatus = '⚠️ UNAVAILABLE (missing on BL)';
  } else if (plVolume === 0) {
    volumeStatus = '⚠️ UNAVAILABLE (missing on PL)';
  } else if (parseFloat(volDiff) > 0.1) {
    volumeStatus = `❌ DISCREPANCY (${volDiff}cbm variance)`;
  } else {
    volumeStatus = '✅ MATCH';
  }

  // ── Check 2: Packaging quantity ────────────────────────────
  const blPallets = getVal(bl, 'metrics.pallet_count');
  const plPallets = getVal(pl, 'metrics.pallet_count');
  const blCartons = getVal(bl, 'metrics.carton_count');
  const plCartons = getVal(pl, 'metrics.carton_count');
  const blPieces  = getVal(bl, 'metrics.piece_count');
  const plPieces  = getVal(pl, 'metrics.piece_count');

  const packagingErrors = [];
  const packagingWarnings = [];

  // Pallets
  if (blPallets === 0 && plPallets === 0) {
    packagingWarnings.push('Pallets: missing on both');
  } else if (blPallets === 0) {
    packagingWarnings.push('Pallets: missing on BL');
  } else if (plPallets === 0) {
    packagingWarnings.push('Pallets: missing on PL');
  } else if (blPallets !== plPallets) {
    packagingErrors.push(`Pallet Mismatch (PL: ${plPallets} vs BL: ${blPallets})`);
  }

  // Cartons
  if (blCartons === 0 && plCartons === 0) {
    packagingWarnings.push('Cartons: missing on both');
  } else if (blCartons === 0) {
    packagingWarnings.push('Cartons: missing on BL');
  } else if (plCartons === 0) {
    packagingWarnings.push('Cartons: missing on PL');
  } else if (blCartons !== plCartons) {
    packagingErrors.push(`Carton Mismatch (PL: ${plCartons} vs BL: ${blCartons})`);
  }

  // Pieces
  if (blPieces === 0 && plPieces === 0) {
    packagingWarnings.push('Pieces: missing on both');
  } else if (blPieces === 0) {
    packagingWarnings.push('Pieces: missing on BL');
  } else if (plPieces === 0) {
    packagingWarnings.push('Pieces: missing on PL');
  } else if (blPieces !== plPieces) {
    packagingErrors.push(`Piece Mismatch (PL: ${plPieces} vs BL: ${blPieces})`);
  }

  let packagingStatus;
  if (packagingErrors.length > 0) {
    packagingStatus = `❌ DISCREPANCY (${packagingErrors.join(' | ')})`;
    if (packagingWarnings.length > 0) {
      packagingStatus += ` | ⚠️ UNAVAILABLE: ${packagingWarnings.join(', ')}`;
    }
  } else if (packagingWarnings.length > 0) {
    packagingStatus = `⚠️ UNAVAILABLE (${packagingWarnings.join(', ')})`;
  } else {
    packagingStatus = '✅ MATCH';
  }

  // ── Check 3: Description ───────────────────────────────────
  const descResult = descriptionOverlap(bl.product, pl.product);
  const descStatus = `${descResult.status} (${descResult.detail})`;

  // ── Overall status ─────────────────────────────────────────
  const hasDiscrepancy = [weightStatus, volumeStatus, packagingStatus, descStatus]
    .some(s => s.startsWith('❌'));
  const hasUnavailable = [weightStatus, volumeStatus, packagingStatus, descStatus]
    .some(s => s.startsWith('⚠️'));

  const overallStatus = hasDiscrepancy
    ? '❌ DISCREPANCY'
    : hasUnavailable
      ? '⚠️ PARTIAL'
      : '✅ MATCH';

  return {
    json: {
      // ── Shipment identity ──────────────────────
      Parent_ID:        input.Parent_ID       || "N/A",
      Match_ID:         input.Match_ID        || "N/A",
      "Booking#":       input["Booking#"]     || "N/A",
      "Booking type":   input["Booking type"] || "N/A",
      "Folder name":    input["Folder name"]  || "N/A",

      // ── Audit result ───────────────────────────
      Overall_Status:       overallStatus,
      Check1_Weight:        weightStatus,
      Check1_Volume:        volumeStatus,
      Check2_Packaging:     packagingStatus,
      Check3_Description:   descStatus,
      Audit_Date:           new Date().toISOString().split('T')[0],
      Audit_Timestamp:      new Date().toISOString(),
      Runtime_Seconds:      runtime,

      // ── Supplier comparison ────────────────────
      BL_Supplier:      bl.factory.name || "NOT_FOUND",
      PL_Supplier:      pl.factory.name || "NOT_FOUND",

      // ── Logistics comparison ───────────────────
      BL_Pallets:       blPallets,
      PL_Pallets:       plPallets,
      BL_Cartons:       blCartons,
      PL_Cartons:       plCartons,
      BL_Pieces:        blPieces,
      PL_Pieces:        plPieces,
      BL_Weight:        blWeight,
      PL_Weight:        plWeight,
      BL_Volume:        blVolume,
      PL_Volume:        plVolume,
      BL_Product:       bl.product,
      PL_Product:       pl.product,

      // ── Variances ──────────────────────────────
      Weight_Variance:  weightDiff,
      Volume_Variance:  volDiff,

      // ── AI metadata ────────────────────────────
      BL_Tokens_Used:   input.BL_tokens_used || 0,
      PL_Tokens_Used:   input.PL_tokens_used || 0,
    }
  };
});

for (const item of items) {
  const rawContent = item.json.BL_content || "";
  const cleanJsonString = rawContent.replace(/```json|```/g, "").trim();

  if (cleanJsonString) {
    try {
      const parsedData = JSON.parse(cleanJsonString);

      item.json = {
        Match_ID:        item.json.Match_ID,
        Parent_ID:       item.json.Parent_ID,
        "Booking#":      item.json["Booking#"],
        "Booking type":  item.json["Booking type"],
        "Folder name":   item.json["Folder name"],
        Document_ID:     item.json.Document_ID,
        Document_name:   item.json.Document_name,
        BL_tokens_used:  item.json.BL_tokens_used || 0,
        BL_factory:             parsedData.factory,
        BL_consignee:           parsedData.consignee,
        BL_logistics_metrics:   parsedData.logistics_metrics,
        BL_cargo_description:   parsedData.cargo_description,
        BL_document_type:       parsedData.document_type
      };

    } catch (error) {
      item.json.error = "Invalid JSON from Gemini";
      item.json.raw_content_debug = cleanJsonString;
    }
  }
}

return items;

const boundary = 'n8n_boundary';
// Use the helper to get the binary data correctly
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');

const header = Buffer.from(
  `--${boundary}\r\n` +
  `Content-Type: application/json; charset=UTF-8\r\n\r\n` +
  `{"mimeType": "application/vnd.google-apps.spreadsheet"}\r\n\r\n` +
  `--${boundary}\r\n` +
  `Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\r\n\r\n`, 
  'utf-8'
);

const footer = Buffer.from(`\r\n--${boundary}--`, 'utf-8');
const combinedBuffer = Buffer.concat([header, binaryData, footer]);

// This clean return prevents the circular structure error
return [
  {
    json: $input.item.json,
    binary: {
      data: {
        data: combinedBuffer.toString('base64'),
        mimeType: `multipart/related; boundary=${boundary}`,
        fileName: 'upload.bin'
      }
    }
  }
];

const sourceItems = $("Edit Fields4").all();

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const source = sourceItems[i]?.json || {};

  try {
    const rawContent = item.json.content?.parts?.[0]?.text || "";
    const cleanJsonString = rawContent.replace(/```json|```/g, "").trim();

    if (cleanJsonString) {
      const parsedData = JSON.parse(cleanJsonString);

      item.json = {
        Match_ID:        source.Match_ID,
        Parent_ID:       source.Parent_ID,
        "Booking#":      source["Booking#"],
        "Booking type":  source["Booking type"],
        "Folder name":   source["Folder name"],
        Document_ID:     source.Document_ID,
        Document_name:   source.Document_name,
        PL_tokens_used:  item.json.usageMetadata?.totalTokenCount || 
                         item.json.usageMetadata?.promptTokenCount || 0,
        PL_factory:           parsedData.factory,
        PL_consignee:         parsedData.consignee,
        PL_logistics_metrics: parsedData.logistics_metrics,
        PL_cargo_description: parsedData.cargo_description,
        PL_document_type:     parsedData.document_type
      };
    }
  } catch (error) {
    item.json.error = "Failed to parse Gemini output";
    item.json.error_details = error.message;
  }
}

return $input.all();
